// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver')
const assert = require('assert')

describe('Untitled', function() {
  this.timeout(30000)
  let driver
  let vars
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build()
    vars = {}
  })
  afterEach(async function() {
    await driver.quit();
  })
  it('Untitled', async function() {
    await driver.findElement(By.id("login_form_email")).sendKeys("vo.khanh.duy")
    await driver.findElement(By.id("login_form_password")).sendKeys("123123")
    await driver.findElement(By.css(".ant-btn")).click()
    await driver.findElement(By.css(".ant-row:nth-child(7) .ant-card-body")).click()
    await driver.findElement(By.name("Search")).click()
    await driver.findElement(By.name("Search")).click()
    await driver.wait(until.elementLocated(By.css(".ant-form-item-control-input-content > .ant-btn svg")), 30000)
    await driver.wait(until.stalenessOf(await driver.findElement(By.css(".ant-form-item-control-input-content > .ant-btn svg"))), 30000)
    await driver.findElement(By.xpath("//*[@id=\"root\"]/section/section/main/div/div[2]/div[1]/div/div/div/div/div/table/tbody/tr[9]/td[1]/span/button")).click()
    await driver.findElement(By.xpath("//*[@id=\"root\"]/section/section/main/div/div[2]/div[1]/div/div/div/div/div/table/tbody/tr[10]/td/div/div/div/div/div/div/table/tbody/tr[4]")).click()
    assert(await driver.findElement(By.css(".ant-card-body > div > .ant-typography")).getText() == "評価目標詳細")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-no-colon")).getText() == "評価期間")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-no-colon")).getText() == "氏名")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-form-item-no-colon")).getText() == "部署")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(5) .ant-form-item-no-colon")).getText() == "等級")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(6) .ant-form-item-no-colon")).getText() == "評価者")
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(7) .ant-form-item-no-colon")).getText() == "状態")
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) > tr:nth-child(1) > .ant-table-cell:nth-child(1)")).getText() == "部門目標")
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(2)")).getText() == "指標・水準 (達成数値)")
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(3)")).getText() == "手段・方法 (どのように)")
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(4)")).getText() == "ウェイト")
  })
})
